program.name("teneo-cli").version("2.0.34").description("Teneo Protocol CLI. Private keys are NEVER transmitted.").option("--json", "Machine-readable JSON output");
program.command("daemon").description("Manage the background daemon (start | stop | status)").argument("<action>", "start | stop | status").action(async (action) => {
  switch (action) {
    case "start": {
      if (isDaemonRunning()) {
        out({ status: "already_running", port: getDaemonPort() });
        return;
      }
      const port = await startDaemon();
      out({ status: "started", port });
      break;
    }
    case "stop": {
      const port = getDaemonPort();
      if (!port || !isDaemonRunning()) {
        out({ status: "not_running" });
        return;
      }
      try {
        await fetch(`http://localhost:${port}/stop`, { method: "POST" });
      } catch {
      }
      out({ status: "stopped" });
      break;
    }
    case "status": {
      const running = isDaemonRunning();
      out({ status: running ? "running" : "stopped", port: getDaemonPort() });
      break;
    }
    default:
      fail(`Unknown daemon action: ${action}. Use: start | stop | status`);
  }
});
